css:
@page {
  size: A4; margin: 16mm 18mm 20mm 18mm;
  @bottom-left { content: "Beispiel Handels GmbH · Marktplatz 1 · 10115 Berlin \A Amtsgericht Charlottenburg · HRB 123456 \A Geschäftsführer: Max Beispiel"; font-size: 6.5pt; line-height: 1.45; color: #8a8a8a; white-space: pre-line; vertical-align: top; padding-top: 4mm; }
  @bottom-center { content: "Seite " counter(page) " von " counter(pages); font-size: 6.5pt; color: #8a8a8a; white-space: nowrap; vertical-align: top; padding-top: 4mm; }
  @bottom-right { content: "USt-IdNr. DE123456789 · St.-Nr. 13/456/78901 \A IBAN DE89 3704 0044 0532 0130 00 · BIC COBADEFFXXX"; font-size: 6.5pt; line-height: 1.45; color: #8a8a8a; white-space: pre-line; text-align: right; vertical-align: top; padding-top: 4mm; }
}

body { color: #0b2545; font-family: 'Helvetica', 'Arial', sans-serif; }
.num { font-variant-numeric: tabular-nums; }
.mono { font-family: 'Courier New', monospace; letter-spacing: -0.02em; }
.r { text-align: right; }
.doc-header { display: block; margin: 0; }

.fi-top { display: flex; align-items: flex-start; justify-content: space-between; padding-bottom: 4mm; border-bottom: 2px solid #0b2545; }
.fi-brand { display: flex; align-items: center; gap: 3mm; }
.fi-mark { height: 9mm; width: 9mm; display: block; }
.fi-brandname { font-size: 12pt; font-weight: 800; }
.fi-doc { text-align: right; }
.fi-eyebrow { display: block; font-size: 9pt; letter-spacing: 0.16em; text-transform: uppercase; color: #b91c1c; font-weight: 800; }
.fi-docno { display: block; font-size: 13pt; font-weight: 800; margin-top: 0.6mm; }
.fi-date { font-size: 8.5pt; color: #6b7890; }

.fi-addr { margin: 6mm 0 4mm; font-size: 10pt; line-height: 1.5; }
.fi-addr__sender { font-size: 7.5pt; color: #6b7890; border-bottom: 1px solid #d6deea; padding-bottom: 1mm; margin-bottom: 2mm; }
.fi-intro { font-size: 9.5pt; color: #3a4863; line-height: 1.5; max-width: 165mm; margin-bottom: 6mm; }

/* Tiles */
.fi-tiles { display: flex; gap: 3mm; margin-bottom: 7mm; }
.fi-tile { flex: 1 1 0; background: #eef2f7; border-radius: 2.5mm; padding: 4mm; }
.fi-tile--accent { background: #0b2545; color: #fff; }
.fi-tile__v { font-size: 14pt; font-weight: 800; letter-spacing: -0.01em; font-variant-numeric: tabular-nums; }
.fi-tile__k { font-size: 7pt; letter-spacing: 0.08em; text-transform: uppercase; color: #6b7890; font-weight: 700; margin-top: 1.5mm; }
.fi-tile--accent .fi-tile__k { color: #9db4d4; }

/* Main */
.fi-main { display: flex; gap: 7mm; align-items: flex-start; margin-bottom: 7mm; }
.fi-open { flex: 1 1 0; }
.fi-h2 { font-size: 8pt; letter-spacing: 0.12em; text-transform: uppercase; color: #0b2545; font-weight: 800; margin: 0 0 3mm; }
.fi-h2--light { color: #9db4d4; }
.fi-table { width: 100%; border-collapse: collapse; }
.fi-table thead th { font-size: 7pt; letter-spacing: 0.08em; text-transform: uppercase; color: #6b7890; font-weight: 700; text-align: left; padding: 0 2mm 2mm; border-bottom: 1px solid #0b2545; }
.fi-table thead th.r { text-align: right; }
.fi-table tbody td { padding: 2.4mm 2mm; border-bottom: 1px solid #e6ebf2; font-size: 9.5pt; }
.fi-table tfoot td { padding: 2.6mm 2mm; font-weight: 800; font-size: 10.5pt; border-top: 2px solid #0b2545; }
.fi-days { font-size: 8.5pt; font-weight: 700; color: #6b7890; }
.fi-days--hot { color: #b91c1c; }

/* Aging chart */
.fi-aging { flex: 0 0 54mm; background: #eef2f7; border-radius: 2.5mm; padding: 4mm; }
.fi-chart { display: flex; align-items: flex-end; justify-content: space-between; gap: 2.5mm; height: 34mm; }
.fi-bar { flex: 1 1 0; display: flex; flex-direction: column; align-items: stretch; height: 100%; justify-content: flex-end; }
.fi-bar__fill { background: #0b2545; border-radius: 1mm 1mm 0 0; min-height: 0.6mm; }
.fi-bar:nth-child(1) .fi-bar__fill { background: #3a4863; }
.fi-bar:nth-child(2) .fi-bar__fill { background: #1d4ed8; }
.fi-bar:nth-child(n+3) .fi-bar__fill { background: #b91c1c; }
.fi-bar__lbl { font-size: 6.5pt; color: #6b7890; text-align: center; margin-top: 1.6mm; }

/* Payment */
.fi-pay { display: flex; gap: 7mm; background: #0b2545; color: #fff; border-radius: 3mm; padding: 5mm 6mm; align-items: center; }
.fi-pay__info { flex: 1 1 0; }
.fi-pay__grid { display: grid; grid-template-columns: 26mm 1fr; gap: 1.4mm 4mm; font-size: 9.5pt; }
.fi-pay__grid span { color: #9db4d4; }
.fi-pay__grid strong { color: #fff; font-weight: 700; }
.fi-pay__qr { flex: 0 0 32mm; text-align: center; }
.fi-pay__qr svg { width: 30mm; height: 30mm; background: #fff; padding: 1.5mm; border-radius: 2mm; }
.fi-pay__qr span { display: block; font-size: 7.5pt; color: #9db4d4; margin-top: 2mm; }
